pragma solidity ^0.8.20;

/**
 * @title AIReputationSystem
 * @dev Decentralized reputation scoring for AI agents with on-chain verification.
 * Implements a weighted scoring mechanism where verified entities can rate agents.
 */

contract AIReputationSystem {
    struct Agent {
        string agentId;
        uint256 totalScore;
        uint256 totalRatings;
        bool isRegistered;
    }

    struct Rating {
        uint8 score; // 1-5
        string comment;
        uint256 timestamp;
    }

    mapping(address => Agent) public agents;
    mapping(address => mapping(address => Rating)) public ratings; // rater => agent => rating
    mapping(address => bool) public verifiedRaters;

    address public owner;
    uint256 public constant MAX_SCORE = 5;

    event AgentRegistered(address indexed agentAddress, string agentId);
    event RatingSubmitted(address indexed rater, address indexed agent, uint8 score);
    event RaterVerified(address indexed rater);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerAgent(string memory _agentId) external {
        require(!agents[msg.sender].isRegistered, "Agent already registered");

        agents[msg.sender] = Agent({
            agentId: _agentId,
            totalScore: 0,
            totalRatings: 0,
            isRegistered: true
        });

        emit AgentRegistered(msg.sender, _agentId);
    }

    function verifyRater(address _rater) external onlyOwner {
        verifiedRaters[_rater] = true;
        emit RaterVerified(_rater);
    }

    /**
     * @dev Submit a rating for an AI agent. 
     * Only verified raters can influence the score to prevent Sybil attacks.
     */
    function rateAgent(address _agent, uint8 _score, string calldata _comment) external {
        require(agents[_agent].isRegistered, "Agent not registered");
        require(_score >= 1 && _score <= MAX_SCORE, "Score must be between 1 and 5");
        require(verifiedRaters[msg.sender], "Only verified raters can submit scores");

        // Calculate weighted score update
        // If user is updating a rating, we subtract the old score first
        if (ratings[msg.sender][_agent].score > 0) {
            agents[_agent].totalScore -= ratings[msg.sender][_agent].score;
            agents[_agent].totalRatings -= 1;
        }

        ratings[msg.sender][_agent] = Rating({
            score: _score,
            comment: _comment,
            timestamp: block.timestamp
        });

        agents[_agent].totalScore += _score;
        agents[_agent].totalRatings += 1;

        emit RatingSubmitted(msg.sender, _agent, _score);
    }

    /**
     * @dev Returns the average reputation score of an AI agent.
     */
    function getReputation(address _agent) external view returns (uint256) {
        Agent storage agent = agents[_agent];
        require(agent.isRegistered, "Agent not registered");
        require(agent.totalRatings > 0, "No ratings available");

        return agent.totalScore / agent.totalRatings;
    }

    function getAgentDetails(address _agent) external view returns (string memory id, uint256 avgScore, uint256 count) {
        Agent storage agent = agents[_agent];
        require(agent.isRegistered, "Agent not registered");

        uint256 avg = agent.totalRatings > 0 ? agent.totalScore / agent.totalRatings : 0;
        return (agent.agentId, avg, agent.totalRatings);
    }
