            metadataURI: _metadataURI,
            totalScore: 0,
            reviewCount: 0,
            isVerified: false
        });
        emit AgentRegistered(msg.sender, _metadataURI);
    }

    /**
     * @dev Submit a performance review for an agent
     * @param _agent The address of the AI agent being reviewed
     * @param _rating Score from 1 to 5
     * @param _comment Textual feedback
     */
