        reviews[_agent][msg.sender] = Review({
            reviewer: msg.sender,
            rating: _rating,
            comment: _comment,
            timestamp: block.timestamp
        });

        agents[_agent].totalScore += _rating;
        agents[_agent].reviewCount++;

        emit ReviewSubmitted(_agent, msg.sender, _rating);
