            isRegistered: true
        });
        emit AgentRegistered(_agent);
    }

    function createTask(bytes32 _taskId, address _agent) external {
        require(agents[_agent].isRegistered, "Agent must be registered");
        tasks[_taskId] = Task({
            agent: _agent,
            client: msg.sender,
            isCompleted: false,
            isVerified: false
        });
        emit TaskCreated(_taskId, _agent);
    }

    /**
     * @dev Verifies task completion and updates reputation.
     * @param _taskId Unique identifier of the task
     * @param _success Whether the agent performed successfully
     */
    function verifyTask(bytes32 _taskId, bool _success) external {
        Task storage task = tasks[_taskId];
        require(msg.sender == task.client, "Only the client can verify the task");
        require(!task.isVerified, "Task already verified");

        task.isCompleted = true;
        task.isVerified = true;

        _updateReputation(task.agent, _success);
    }

    function _updateReputation(address _agent, bool _success) internal {
        Agent storage agent = agents[_agent];

        agent.totalTasks++;
        if (_success) {
            agent.positiveReviews++;
        } else {
            agent.negativeReviews++;
        }

        // Calculate Reputation Score: (Positive / Total) * 10000
        // This ensures a precision of 2 decimal places
        agent.reputationScore = (agent.positiveReviews * SCORE_SCALE) / agent.totalTasks;

        emit ReputationUpdated(_agent, agent.reputationScore);
    }

    function getAgentScore(address _agent) external view returns (uint256) {
        require(agents[_agent].isRegistered, "Agent not registered");
        return agents[_agent].reputationScore;
    }

    function getAgentStats(address _agent) external view returns (uint256 total, uint256 pos, uint256 neg) {
        Agent storage agent = agents[_agent];
        return (agent.totalTasks, agent.positiveReviews, agent.negativeReviews);
    }
